package dev.helios.app.service;

import dev.helios.app.model.Post;
import dev.helios.app.repository.PostRepository;
import org.springframework.stereotype.Service;
import java.util.UUID;
import java.util.List;
import java.util.Optional;

@Service
public class PostService {

    private final PostRepository repo;

    public PostService(PostRepository repo) {
        this.repo = repo;
    }

    public List<Post> findAll() {
        return repo.findAll();
    }

    public Optional<Post> findById(UUID id) {
        return repo.findById(id);
    }

    public Post create(Post post) {
        return repo.save(post);
    }

    public Optional<Post> update(UUID id, Post updates) {
        return repo.findById(id).map(existing -> {
            if (updates.getTitle() != null) existing.setTitle(updates.getTitle());
            if (updates.getBody() != null) existing.setBody(updates.getBody());
            if (updates.getPublished() != null) existing.setPublished(updates.getPublished());
            return repo.save(existing);
        });
    }

    public boolean delete(UUID id) {
        if (!repo.existsById(id)) return false;
        repo.deleteById(id);
        return true;
    }
}

